  6→// This file contains the API types and data fetching logic for querying metric data
  7→// from the in-memory metric store. It provides structures for building complex queries
  8→// with support for aggregation, scaling, padding, and statistics computation.
  9→package metricstore
 10→
 11→import (
 12→	"errors"
 13→	"fmt"
 14→	"math"
 15→
 16→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 17→	"github.com/ClusterCockpit/cc-lib/v2/schema"
 18→	"github.com/ClusterCockpit/cc-lib/v2/util"
 19→)
 20→
 21→var (
 22→	// ErrNoHostOrMetric is returned when the metric store does not find the host or the metric
 23→	ErrNoHostOrMetric error = errors.New("[METRICSTORE]> metric or host not found")
 24→	// ErrInvalidTimeRange is returned when a query has 'from' >= 'to'
 25→	ErrInvalidTimeRange = errors.New("[METRICSTORE]> invalid time range: 'from' must be before 'to'")
 26→	// ErrEmptyCluster is returned when a query with ForAllNodes has no cluster specified
 27→	ErrEmptyCluster = errors.New("[METRICSTORE]> cluster name cannot be empty")
 28→)
 29→
 30→// APIMetricData represents the response data for a single metric query.
 31→//
 32→// It contains both the time-series data points and computed statistics (avg, min, max).
 33→// If an error occurred during data retrieval, the Error field will be set and other
 34→// fields may be incomplete.
 35→type APIMetricData struct {
 36→	Error      *string           `json:"error,omitempty"`
 37→	Data       schema.FloatArray `json:"data,omitempty"`
 38→	From       int64             `json:"from"`
 39→	To         int64             `json:"to"`
 40→	Resolution int64             `json:"resolution"`
 41→	Avg        schema.Float      `json:"avg"`
 42→	Min        schema.Float      `json:"min"`
 43→	Max        schema.Float      `json:"max"`
 44→}
 45→
 46→// APIQueryRequest represents a batch query request for metric data.
 47→//
 48→// It supports two modes of operation:
 49→//  1. Explicit queries via the Queries field
 50→//  2. Automatic query generation via ForAllNodes (queries all specified metrics for all nodes in the cluster)
 51→//
 52→// The request can be customized with flags to include/exclude statistics, raw data, and padding.
 53→type APIQueryRequest struct {
 54→	Cluster     string     `json:"cluster"`
 55→	Queries     []APIQuery `json:"queries"`
 56→	ForAllNodes []string   `json:"for-all-nodes"`
 57→	From        int64      `json:"from"`
 58→	To          int64      `json:"to"`
 59→	WithStats   bool       `json:"with-stats"`
 60→	WithData    bool       `json:"with-data"`
 61→	WithPadding bool       `json:"with-padding"`
 62→}
 63→
 64→// APIQueryResponse represents the response to an APIQueryRequest.
 65→//
 66→// Results is a 2D array where each outer element corresponds to a query,
 67→// and each inner element corresponds to a selector within that query
 68→// (e.g., multiple CPUs or cores).
 69→type APIQueryResponse struct {
 70→	Queries []APIQuery        `json:"queries,omitempty"`
 71→	Results [][]APIMetricData `json:"results"`
 72→}
 73→
 74→// APIQuery represents a single metric query with optional hierarchical selectors.
 75→//
 76→// The hierarchical selection works as follows:
 77→//   - Hostname: The node to query
 78→//   - Type + TypeIds: First level of hierarchy (e.g., "cpu" + ["0", "1", "2"])
 79→//   - SubType + SubTypeIds: Second level of hierarchy (e.g., "core" + ["0", "1"])
 80→//
 81→// If Aggregate is true, data from multiple type/subtype IDs will be aggregated according
 82→// to the metric's aggregation strategy. Otherwise, separate results are returned for each combination.
 83→type APIQuery struct {
 84→	Type        *string      `json:"type,omitempty"`
 85→	SubType     *string      `json:"subtype,omitempty"`
 86→	Metric      string       `json:"metric"`
 87→	Hostname    string       `json:"host"`
 88→	Resolution  int64        `json:"resolution"`
 89→	TypeIds     []string     `json:"type-ids,omitempty"`
 90→	SubTypeIds  []string     `json:"subtype-ids,omitempty"`
 91→	ScaleFactor schema.Float `json:"scale-by,omitempty"`
 92→	Aggregate   bool         `json:"aggreg"`
 93→}
 94→
 95→// AddStats computes and populates the Avg, Min, and Max fields from the Data array.
 96→//
 97→// NaN values in the data are ignored during computation. If all values are NaN,
 98→// the statistics fields will be set to NaN.
 99→//
100→// TODO: Optimize this, just like the stats endpoint!
101→func (data *APIMetricData) AddStats() {
102→	n := 0
103→	sum, min, max := 0.0, math.MaxFloat64, -math.MaxFloat64
104→	for _, x := range data.Data {
105→		if x.IsNaN() {
106→			continue
107→		}
108→
109→		n += 1
110→		sum += float64(x)
111→		min = math.Min(min, float64(x))
112→		max = math.Max(max, float64(x))
113→	}
114→
115→	if n > 0 {
116→		avg := sum / float64(n)
117→		data.Avg = schema.Float(avg)
118→		data.Min = schema.Float(min)
119→		data.Max = schema.Float(max)
120→	} else {
121→		data.Avg, data.Min, data.Max = schema.NaN, schema.NaN, schema.NaN
122→	}
123→}
124→
125→// ScaleBy multiplies all data points and statistics by the given factor.
126→//
127→// This is commonly used for unit conversion (e.g., bytes to gigabytes).
128→// Scaling by 0 or 1 is a no-op for performance reasons.
129→func (data *APIMetricData) ScaleBy(f schema.Float) {
130→	if f == 0 || f == 1 {
131→		return
132→	}
133→
134→	data.Avg *= f
135→	data.Min *= f
136→	data.Max *= f
137→	for i := 0; i < len(data.Data); i++ {
138→		data.Data[i] *= f
139→	}
140→}
141→
142→// PadDataWithNull pads the beginning of the data array with NaN values if needed.
143→//
144→// This ensures that the data aligns with the requested 'from' timestamp, even if
145→// the metric store doesn't have data for the earliest time points. This is useful
146→// for maintaining consistent array indexing across multiple queries.
147→//
148→// Parameters:
149→//   - ms: MemoryStore instance to lookup metric configuration
150→//   - from: The requested start timestamp
151→//   - to: The requested end timestamp (unused but kept for API consistency)
152→//   - metric: The metric name to lookup frequency information
153→func (data *APIMetricData) PadDataWithNull(ms *MemoryStore, from, to int64, metric string) {
154→	minfo, ok := ms.Metrics[metric]
155→	if !ok {
156→		return
157→	}
158→
159→	if (data.From / minfo.Frequency) > (from / minfo.Frequency) {
160→		padfront := int((data.From / minfo.Frequency) - (from / minfo.Frequency))
161→		ndata := make([]schema.Float, 0, padfront+len(data.Data))
162→		for range padfront {
163→			ndata = append(ndata, schema.NaN)
164→		}
165→		for j := 0; j < len(data.Data); j++ {
166→			ndata = append(ndata, data.Data[j])
167→		}
168→		data.Data = ndata
169→	}
170→}
