178→//   - Optional statistics computation (avg, min, max)
179→//   - Optional data scaling
180→//   - Optional data padding with NaN values
181→//
182→// The function constructs selectors based on the query parameters and calls MemoryStore.Read()
183→// for each selector. If a query specifies Aggregate=false with multiple type/subtype IDs,
184→// separate results are returned for each combination.
185→//
186→// Parameters:
187→//   - req: The query request containing queries, time range, and options
188→//
189→// Returns:
190→//   - APIQueryResponse containing results for each query, or error if validation fails
191→//
192→// Errors:
193→//   - ErrInvalidTimeRange if req.From > req.To
194→//   - ErrEmptyCluster if req.ForAllNodes is used without specifying a cluster
195→//   - Error if MemoryStore is not initialized
196→//   - Individual query errors are stored in APIMetricData.Error field
197→func FetchData(req APIQueryRequest) (*APIQueryResponse, error) {
198→	if req.From > req.To {
199→		return nil, ErrInvalidTimeRange
200→	}
201→	if req.Cluster == "" && req.ForAllNodes != nil {
202→		return nil, ErrEmptyCluster
203→	}
204→
205→	req.WithData = true
206→	ms := GetMemoryStore()
207→	if ms == nil {
208→		return nil, fmt.Errorf("[METRICSTORE]> memorystore not initialized")
209→	}
210→
211→	response := APIQueryResponse{
212→		Results: make([][]APIMetricData, 0, len(req.Queries)),
213→	}
214→	if req.ForAllNodes != nil {
215→		nodes := ms.ListChildren([]string{req.Cluster})
216→		for _, node := range nodes {
217→			for _, metric := range req.ForAllNodes {
218→				q := APIQuery{
219→					Metric:   metric,
220→					Hostname: node,
221→				}
222→				req.Queries = append(req.Queries, q)
223→				response.Queries = append(response.Queries, q)
224→			}
225→		}
226→	}
227→
228→	for _, query := range req.Queries {
229→		sels := make([]util.Selector, 0, 1)
230→		if query.Aggregate || query.Type == nil {
231→			sel := util.Selector{{String: req.Cluster}, {String: query.Hostname}}
232→			if query.Type != nil {
233→				if len(query.TypeIds) == 1 {
234→					sel = append(sel, util.SelectorElement{String: *query.Type + query.TypeIds[0]})
235→				} else {
236→					ids := make([]string, len(query.TypeIds))
237→					for i, id := range query.TypeIds {
238→						ids[i] = *query.Type + id
239→					}
240→					sel = append(sel, util.SelectorElement{Group: ids})
241→				}
242→
243→				if query.SubType != nil {
244→					if len(query.SubTypeIds) == 1 {
245→						sel = append(sel, util.SelectorElement{String: *query.SubType + query.SubTypeIds[0]})
246→					} else {
247→						ids := make([]string, len(query.SubTypeIds))
248→						for i, id := range query.SubTypeIds {
249→							ids[i] = *query.SubType + id
250→						}
251→						sel = append(sel, util.SelectorElement{Group: ids})
252→					}
253→				}
254→			}
255→			sels = append(sels, sel)
256→		} else {
257→			for _, typeID := range query.TypeIds {
258→				if query.SubType != nil {
259→					for _, subTypeID := range query.SubTypeIds {
260→						sels = append(sels, util.Selector{
261→							{String: req.Cluster},
262→							{String: query.Hostname},
263→							{String: *query.Type + typeID},
264→							{String: *query.SubType + subTypeID},
265→						})
266→					}
267→				} else {
268→					sels = append(sels, util.Selector{
269→						{String: req.Cluster},
270→						{String: query.Hostname},
271→						{String: *query.Type + typeID},
272→					})
273→				}
274→			}
275→		}
276→
277→		var err error
278→		res := make([]APIMetricData, 0, len(sels))
279→		for _, sel := range sels {
280→			data := APIMetricData{}
281→
282→			data.Data, data.From, data.To, data.Resolution, err = ms.Read(sel, query.Metric, req.From, req.To, query.Resolution)
283→			if err != nil {
284→				// Skip Error If Just Missing Host or Metric, Continue
285→				// Empty Return For Metric Handled Gracefully By Frontend
286→				if err != ErrNoHostOrMetric {
287→					msg := err.Error()
288→					data.Error = &msg
289→					res = append(res, data)
290→				} else {
291→					cclog.Warnf("failed to fetch '%s' from host '%s' (cluster: %s): %s", query.Metric, query.Hostname, req.Cluster, err.Error())
292→				}
293→				continue
294→			}
295→
296→			if req.WithStats {
297→				data.AddStats()
298→			}
299→			if query.ScaleFactor != 0 {
300→				data.ScaleBy(query.ScaleFactor)
301→			}
302→			if req.WithPadding {
303→				data.PadDataWithNull(ms, req.From, req.To, query.Metric)
304→			}
305→			if !req.WithData {
306→				data.Data = nil
307→			}
308→			res = append(res, data)
309→		}
310→		response.Results = append(response.Results, res)
311→	}
312→
313→	return &response, nil
314→}
